template.script:
(function () {
    'use strict';

    var table    = document.getElementById('s01dnTable');
    var searchIn = document.getElementById('filterSearch');
    var dfIn     = document.getElementById('s01dnDateFrom');
    var dtIn     = document.getElementById('s01dnDateTo');
    var targetMoveSel = document.getElementById('s01dnTargetMove');
    var drIn = document.getElementById('s01dnDateRange');
    if (drIn) {
        var drId = drIn.getAttribute('data-initial-id');
        if (drId) drIn.value = drId;
    }


    var toolbar  = document.getElementById('s01dnToolbar');
    var toolbarBody = document.getElementById('s01dnToolbarBody');
    var btnFilterToggle = document.getElementById('s01dnFilterToggle');
    var screenTableHost = document.getElementById('s01dnScreenTableHost');
    var printChunkWrap = document.getElementById('s01dnPrintChunkWrap');
    if (targetMoveSel) {
        var tmv = targetMoveSel.getAttribute('data-initial-wizard');
        if (tmv === 'posted' || tmv === 'all') {
            targetMoveSel.value = tmv;
        }
    }

    if (!table) return;

    /** Trang 1: nhật ký A–I + F–G; các trang sau: Diễn giải (E) + H + tối đa N TK (sổ cái). */
    var S01DN_ACCOUNTS_PER_PRINT_PAGE = 12;
    /**
     * A3 ngang + @page margin 2cm trên / 2.5cm dưới: thân trang ≈ 297 − 20 − 25 mm.
     * Bề ngang đo layout (CSS .s01dn-measure-layout width) phải khớp lề in: 420−30−10 mm.
     * Nếu đổi khổ/margin @page — cập nhật đồng thời S01DN_PAGE_BODY_H_PX và width trong CSS.
     */
    var S01DN_PRINT_MM_TO_PX = 96 / 25.4;
    /** Dự phòng khi không đọc được #s01dnPageBodyProbe (fallback 96dpi). */
    var S01DN_PAGE_BODY_H_PX = (297 - 20 - 25) * S01DN_PRINT_MM_TO_PX;
    /**
     * Trừ px: thead lặp trên mỗi trang bảng, làm tròn, orphan/widow — engine in thường chia sớm hơn DOM.
     */
    var S01DN_PAGE_BODY_FUDGE_PX = 52;
    /**
     * Dự phòng thêm cho @page @bottom-right (\"Trang xx / yy\") + lệch Chromium so với vùng nội dung.
     */
    var S01DN_PAGE_BODY_PRINT_MARGIN_BOX_PX = 40;
    /** Cộng vào chiều cao mỗi dòng tbody khi mô phỏng (px) — bù làm tròn / subpixel. */
    var S01DN_SIM_ROW_SLACK_PX = 0.45;
    /** Khi có mục lục: chuyển #s01dnReportPrintHeader xuống chunk nhật ký — khôi phục khi đóng in. */
    var S01DN_PRINT_HEADER_RESTORE = null;

    function s01dnEffectivePageBodyPx() {
        var base = S01DN_PAGE_BODY_H_PX;
        var probe = document.getElementById('s01dnPageBodyProbe');
        if (probe) {
            try {
                void probe.offsetHeight;
                var rh = probe.getBoundingClientRect().height;
                if (rh > 80) {
                    base = rh;
                }
            } catch (e) {
                /* fallback S01DN_PAGE_BODY_H_PX */
            }
        }
        return Math.max(
            120,
            base
                - S01DN_PAGE_BODY_FUDGE_PX
                - S01DN_PAGE_BODY_PRINT_MARGIN_BOX_PX,
        );
    }

    /** Xóa placeholder dòng số trang (in thật dùng @page @bottom-left + counter(pages)). */
    function s01dnClearFooterBookPagesLine() {
        var el = document.getElementById('s01dnFooterBookPagesLine');
        if (el) el.textContent = '';
    }

    /** Luôn lấy #s01dnTable hiện tại (sau AJAX innerHTML node cũ bị thay — không giữ ref cũ). */
    function s01dnRefreshTableRef() {
        table = document.getElementById('s01dnTable');
        return table;
    }

    function s01dnRefreshFooterBookPagesOnly() {
        if (!printChunkWrap || !printChunkWrap.classList.contains('s01dn-print-chunks-ready')) {
            return;
        }
        var pageBodyPx = s01dnEffectivePageBodyPx();
        document.body.classList.add('s01dn--measuring-print');
        try {
            void printChunkWrap.offsetHeight;
            s01dnRunPrintPageSimulation(pageBodyPx);
        } finally {
            document.body.classList.remove('s01dn--measuring-print');
        }
    }

    function s01dnFinalizePrintChunks() {
        s01dnSyncSheetInnerWidth();
        void printChunkWrap && printChunkWrap.offsetHeight;
    }

    function s01dnAccIdFromCell(el) {
        if (!el || !el.classList) return null;
        var cl = el.classList;
        for (var i = 0; i < cl.length; i++) {
            var m = cl[i].match(/^acc-(\d+)$/);
            if (m) return parseInt(m[1], 10);
        }
        return null;
    }

    function s01dnStripIds(root) {
        if (!root || !root.querySelectorAll) return;
        var nodes = root.querySelectorAll('[id]');
        for (var i = 0; i < nodes.length; i++) {
            nodes[i].removeAttribute('id');
        }
    }

    /** Tổng số cột hiệu dụng (cộng colspan) để gán colspan cho hàng mục lục in. */
    function s01dnTableColCount(tbl) {
        var tr = tbl.querySelector('tbody tr');
        if (!tr) {
            tr = tbl.querySelector('thead tr:last-of-type');
        }
        if (!tr) return 1;
        var n = 0;
        for (var c = 0; c < tr.cells.length; c++) {
            n += tr.cells[c].colSpan || 1;
        }
        return n;
    }

    /** Mã TK từ thead (sau khi đã strip cột — chỉ phần sổ cái). */
    function s01dnLedgerAccountCodesFromTable(tbl) {
        var tr = tbl.querySelector('thead tr');
        if (!tr) return [];
        var out = [];
        var ths = tr.querySelectorAll('th.acc-col');
        for (var i = 0; i < ths.length; i++) {
            var m = String(ths[i].textContent || '').match(/TK\s*(\S+)/);
            if (m) out.push(m[1]);
        }
        return out;
    }

    var S01DN_SUMMARY_JOURNAL =
        'Nhật ký chung — các chỉ tiêu cột A, B, C, D, E, cột 1 (số tiền phát sinh), I; ' +
        'cột đối ứng F, G; theo Mẫu số S01-DN (Thông tư 200/2014/TT-BTC).';

    function s01dnSummaryLedgerLine(codesText) {
        return (
            'Chi tiết theo tài khoản — các TK: ' + codesText + '; ' +
            'cột Diễn giải (E), thứ tự dòng (H), các cặp Nợ/Có theo số thứ tự cột TT200.'
        );
    }

    /** Hậu tố mục lục theo tờ: nhật ký / từng khối TK (tránh lặp nhãn giống hệt). */
    function s01dnTocChunkSuffix(meta) {
        if (!meta) return '';
        if (meta.kind === 'journal') {
            return 'Nhật ký chung';
        }
        var c = meta.codesText || '(theo bảng)';
        return 'TK ' + String(c).trim();
    }

    function s01dnTocHeadingLine(baseLabel, meta) {
        var b = String(baseLabel || '').trim();
        var s = s01dnTocChunkSuffix(meta);
        if (!s) return b;
        return b + ' - ' + s;
    }

    /** Các dòng diễn giải dùng làm mục lục (khớp cột Diễn giải trên sổ). */
    var S01DN_TOC_HEADING_TYPES = {
        opening: true,
        'month-header': true,
        'summary-period': true,
        'summary-closing': true,
        'summary-cumul': true,
    };

    function s01dnMaybeRecordHeading(tr, page, headingState, meta) {
        if (!tr || !headingState) return;
        var rt = tr.getAttribute('data-row-type');
        if (!S01DN_TOC_HEADING_TYPES[rt]) return;
        var td = tr.querySelector('td.desc');
        var label = (td && String(td.textContent || '').trim()) || '';
        if (!label) return;
        headingState.entries.push({
            label: s01dnTocHeadingLine(label, meta),
            page: page,
            anchorId: tr.id || '',
        });
    }

    /**
     * Một lần duyệt tbody: mọi dòng heading (theo thứ tự dòng).
     * Lặp lại cho từng tờ in (nhật ký + từng khối sổ TK) để đủ chỗ giữ chỗ mục lục.
     */
    function s01dnCollectHeadingTocLabelsStatic() {
        var tbl = document.getElementById('s01dnTable');
        if (!tbl) return [];
        var tbody = tbl.querySelector('tbody');
        if (!tbody) return [];
        var trs = tbody.querySelectorAll('tr');
        var oneSheet = [];
        for (var ti = 0; ti < trs.length; ti++) {
            var tr = trs[ti];
            var rt = tr.getAttribute('data-row-type');
            if (!S01DN_TOC_HEADING_TYPES[rt]) continue;
            var td = tr.querySelector('td.desc');
            var label = (td && String(td.textContent || '').trim()) || '';
            if (label) oneSheet.push(label);
        }
        var suffixes = [];
        if (
            printChunkWrap &&
            printChunkWrap.classList.contains('s01dn-print-chunks-ready')
        ) {
            var hasJ2 = printChunkWrap.querySelector(
                '.s01dn-print-chunk--journal',
            );
            var led2 = printChunkWrap.querySelectorAll(
                '.s01dn-print-chunk--ledger',
            );
            if (hasJ2) suffixes.push('Nhật ký chung');
            for (var si = 0; si < led2.length; si++) {
                var c2 =
                    led2[si].getAttribute('data-s01dn-ledger-codes') ||
                    '(theo bảng)';
                suffixes.push('TK ' + String(c2).trim());
            }
        }
        if (suffixes.length < 1) suffixes.push('Nhật ký chung');
        var out = [];
        for (var sh = 0; sh < suffixes.length; sh++) {
            for (var j = 0; j < oneSheet.length; j++) {
                out.push(oneSheet[j] + ' - ' + suffixes[sh]);
            }
        }
        return out;
    }

    /**
     * Gán id neo cho từng dòng heading trên bản in (nhật ký rồi từng khối sổ),
     * thứ tự khớp mô phỏng mục lục — dùng cho liên kết #fragment.
     */
    function s01dnAssignHeadingAnchorIds() {
        if (!printChunkWrap) return;
        var seq = 0;
        function walkChunk(chunkEl) {
            if (!chunkEl) return;
            var tbl = chunkEl.querySelector('table');
            if (!tbl) return;
            var tbody = tbl.querySelector('tbody');
            if (!tbody) return;
            var trs = tbody.querySelectorAll('tr');
            for (var ri = 0; ri < trs.length; ri++) {
                var tr = trs[ri];
                var rt = tr.getAttribute('data-row-type');
                if (!S01DN_TOC_HEADING_TYPES[rt]) continue;
                tr.id = 's01dn-toc-h-' + seq;
                seq++;
            }
        }
        var jc = printChunkWrap.querySelector('.s01dn-print-chunk--journal');
        walkChunk(jc);
        var led = printChunkWrap.querySelectorAll('.s01dn-print-chunk--ledger');
        for (var li = 0; li < led.length; li++) {
            walkChunk(led[li]);
        }
    }

    /** Chiều cao bố cục gồm margin dọc (offsetHeight không tính margin). */
    function s01dnMeasureBlockHeight(el) {
        if (!el) return 0;
        var h = el.offsetHeight;
        var sh = el.scrollHeight;
        var base = Math.ceil(Math.max(h || 0, sh || 0));
        try {
            var st = window.getComputedStyle(el);
            var mt = parseFloat(st.marginTop) || 0;
            var mb = parseFloat(st.marginBottom) || 0;
            return Math.ceil(base + mt + mb);
        } catch (e) {
            return base;
        }
    }

    function s01dnNewSimState(pageBodyPx) {
        return {
            cursor: 1,
            used: 0,
            pageH: pageBodyPx,
            summaries: [],
        };
    }

    function s01dnEnsureSummaries(state) {
        while (state.summaries.length < state.cursor) {
            state.summaries.push('');
        }
    }

    function s01dnMergeSummary(state, txt) {
        if (!txt) return;
        s01dnEnsureSummaries(state);
        var ix = state.cursor - 1;
        if (state.summaries[ix]) state.summaries[ix] += '; ';
        state.summaries[ix] += txt;
    }

    /** Khối cao h: gán nhãn tờ đầu / tờ tiếp theo của khối (theo từng tờ in). */
    function s01dnConsumeBlockHeight(state, h, labelFirst, labelCont) {
        if (h < 1e-3) return;
        var started = false;
        while (h > 1e-3) {
            var space = state.pageH - state.used;
            var take = Math.min(h, space);
            if (take < 1e-3) {
                state.cursor++;
                state.used = 0;
                continue;
            }
            s01dnMergeSummary(state, !started ? labelFirst : labelCont);
            started = true;
            state.used += take;
            h -= take;
            if (h > 1e-3) {
                state.cursor++;
                state.used = 0;
            }
        }
    }

    function s01dnBreakBeforeNextChunk(state) {
        if (state.used > 1e-3) {
            state.cursor++;
            state.used = 0;
        }
    }

    function s01dnFinalizeSimTotalPages(state) {
        return state.used > 1e-3 ? state.cursor : Math.max(1, state.cursor - 1);
    }

    function s01dnConsumeTocChunkParts(state, tocChunk) {
        if (!tocChunk) return;
        var tocHdr = tocChunk.querySelector('.s01dn-print-toc-header-clone');
        if (tocHdr) {
            s01dnConsumeBlockHeight(
                state,
                s01dnMeasureBlockHeight(tocHdr),
                'Mục lục — khối tiêu đề (đơn vị, S01-DN, kỳ)',
                'Mục lục (tiếp)',
            );
        }
        var title = tocChunk.querySelector('.s01dn-print-toc-title');
        var tbl = tocChunk.querySelector('.s01dn-print-toc-table');
        s01dnConsumeBlockHeight(
            state,
            s01dnMeasureBlockHeight(title),
            'Mục lục — tiêu đề',
            'Mục lục — tiêu đề (tiếp)',
        );
        if (!tbl) return;
        var ith = tbl.querySelector('thead');
        var itb = tbl.querySelector('tbody');
        if (ith) {
            s01dnConsumeBlockHeight(
                state,
                s01dnMeasureBlockHeight(ith),
                'Mục lục — tiêu đề bảng',
                'Mục lục (tiếp)',
            );
        }
        if (itb) {
            var trs = itb.querySelectorAll('tr');
            for (var ri = 0; ri < trs.length; ri++) {
                s01dnConsumeBlockHeight(
                    state,
                    s01dnMeasureBlockHeight(trs[ri]),
                    'Mục lục — danh sách theo từng trang',
                    'Mục lục (tiếp)',
                );
            }
        }
    }

    function s01dnPaginateDataTableChunk(chunkEl, state, meta) {
        if (!chunkEl) return;
        var lh = meta && meta.leadingHeaderEl;
        if (lh) {
            s01dnConsumeBlockHeight(
                state,
                s01dnMeasureBlockHeight(lh),
                'Tiêu đề báo cáo, đơn vị, kỳ, Mẫu S01-DN',
                'Tiêu đề (tiếp)',
            );
        }
        var tbl = chunkEl.querySelector('table');
        if (!tbl) return;
        var thead = tbl.querySelector('thead');
        var tbody = tbl.querySelector('tbody');
        if (!tbody) return;
        var slack = S01DN_SIM_ROW_SLACK_PX;
        var theadH = s01dnMeasureBlockHeight(thead) + slack;
        var trs = tbody.querySelectorAll('tr');
        var headingState = meta && meta.headingState;
        var i = 0;
        while (i < trs.length) {
            var curPage = state.cursor;
            var rowH = s01dnMeasureBlockHeight(trs[i]) + slack;
            var atTop = state.used < 1e-3;
            var leader = atTop ? theadH : 0;
            var need = rowH + leader;
            var space = state.pageH - state.used;
            if (need <= space + 1e-3) {
                if (leader > 1e-3) {
                    var isCont = i > 0;
                    var lbl =
                        meta.kind === 'journal'
                            ? isCont
                                ? S01DN_SUMMARY_JOURNAL + ' (tiếp)'
                                : S01DN_SUMMARY_JOURNAL
                            : isCont
                              ? s01dnSummaryLedgerLine(meta.codesText) + ' (tiếp)'
                              : s01dnSummaryLedgerLine(meta.codesText);
                    s01dnMergeSummary(state, lbl);
                }
                state.used += need;
                if (headingState) {
                    s01dnMaybeRecordHeading(trs[i], curPage, headingState, meta);
                }
                i++;
            } else {
                if (atTop && need > state.pageH + 1e-3) {
                    var isC = i > 0;
                    var lb =
                        meta.kind === 'journal'
                            ? isC
                                ? S01DN_SUMMARY_JOURNAL + ' (tiếp)'
                                : S01DN_SUMMARY_JOURNAL
                            : isC
                              ? s01dnSummaryLedgerLine(meta.codesText) + ' (tiếp)'
                              : s01dnSummaryLedgerLine(meta.codesText);
                    s01dnMergeSummary(state, lb);
                    if (headingState) {
                        s01dnMaybeRecordHeading(trs[i], curPage, headingState, meta);
                    }
                    state.cursor++;
                    state.used = 0;
                    i++;
                } else {
                    state.cursor++;
                    state.used = 0;
                }
            }
        }
    }

    /** Mô phỏng phân trang (mục lục / tóm tắt theo trang). Dòng “Sổ này có … trang” lấy từ @page margin. */
    function s01dnRunPrintPageSimulationOnce(pageBodyPx) {
        var headerEl = document.getElementById('s01dnReportPrintHeader');
        var footerEl = document.getElementById('s01dnReportPrintFooter');
        var tocChunk = printChunkWrap.querySelector('.s01dn-print-chunk--toc');
        var journalChunk = printChunkWrap.querySelector('.s01dn-print-chunk--journal');
        var ledgerChunks = printChunkWrap.querySelectorAll('.s01dn-print-chunk--ledger');
        var state = s01dnNewSimState(pageBodyPx);
        var headingState = { entries: [] };
        var headerInJournal =
            headerEl &&
            journalChunk &&
            journalChunk.contains(headerEl);
        if (!headerInJournal) {
            s01dnConsumeBlockHeight(
                state,
                s01dnMeasureBlockHeight(headerEl),
                'Tiêu đề báo cáo, đơn vị, kỳ, Mẫu S01-DN',
                'Tiêu đề (tiếp)',
            );
        }
        s01dnConsumeTocChunkParts(state, tocChunk);
        s01dnBreakBeforeNextChunk(state);
        s01dnPaginateDataTableChunk(journalChunk, state, {
            kind: 'journal',
            codesText: '',
            headingState: headingState,
            leadingHeaderEl: headerInJournal ? headerEl : null,
        });
        for (var li = 0; li < ledgerChunks.length; li++) {
            s01dnBreakBeforeNextChunk(state);
            var codes = ledgerChunks[li].getAttribute('data-s01dn-ledger-codes') || '(theo bảng)';
            s01dnPaginateDataTableChunk(ledgerChunks[li], state, {
                kind: 'ledger',
                codesText: codes,
                headingState: headingState,
            });
        }
        s01dnConsumeBlockHeight(
            state,
            s01dnMeasureBlockHeight(footerEl),
            'Phần ký: người ghi sổ, kế toán trưởng, giám đốc; ngày mở sổ',
            'Phần ký (tiếp)',
        );
        var total = s01dnFinalizeSimTotalPages(state);
        var sumOut = state.summaries.slice(0, total);
        while (sumOut.length < total) sumOut.push('');
        return {
            totalPages: total,
            summaries: sumOut,
            headingToc: headingState.entries.slice(),
        };
    }

    function s01dnRunPrintPageSimulation(pageBodyPx) {
        return s01dnRunPrintPageSimulationOnce(pageBodyPx);
    }

    function s01dnFillTocPlaceholderRows(tbody, n, labelHints) {
        if (!tbody) return;
        tbody.innerHTML = '';
        for (var i = 0; i < n; i++) {
            var tr = document.createElement('tr');
            var tdP = document.createElement('td');
            tdP.className = 's01dn-print-toc-col-page';
            tdP.textContent = '\u2014';
            var tdS = document.createElement('td');
            tdS.className = 's01dn-print-toc-summary';
            var hint =
                labelHints && labelHints[i]
                    ? String(labelHints[i]).trim()
                    : '';
            tdS.textContent = hint
                ? hint +
                  ' — Mục lục (giữ chỗ chiều cao; theo diễn giải cột E trên sổ).'
                : 'Trang ' +
                  String(i + 1) +
                  ' — Mục lục (giữ chỗ; độ cao gần nội dung thật). Nội dung báo cáo S01-DN theo từng tờ in.';
            tr.appendChild(tdS);
            tr.appendChild(tdP);
            tbody.appendChild(tr);
        }
    }

    function s01dnFinalizeTocPerPage() {
        if (!printChunkWrap || !printChunkWrap.classList.contains('s01dn-print-chunks-ready')) {
            return;
        }
        var tocChunk = printChunkWrap.querySelector('.s01dn-print-chunk--toc');
        if (!tocChunk) return;
        var tocTable = tocChunk.querySelector('.s01dn-print-toc-table');
        if (!tocTable) return;
        var tbody = tocTable.querySelector('tbody');
        if (!tbody) return;
        var pageBodyPx = s01dnEffectivePageBodyPx();
        var staticLabels = s01dnCollectHeadingTocLabelsStatic();
        var useHeadingToc = staticLabels.length > 0;
        var tocPlaceholderRows = useHeadingToc ? staticLabels.length : 6;
        var prevTotal = -1;
        var sim = { totalPages: 1, summaries: [], headingToc: [] };
        document.body.classList.add('s01dn--measuring-print');
        try {
            for (var iter = 0; iter < 28; iter++) {
                s01dnFillTocPlaceholderRows(
                    tbody,
                    tocPlaceholderRows,
                    useHeadingToc ? staticLabels : null,
                );
                void printChunkWrap.offsetHeight;
                void tocChunk.offsetHeight;
                sim = s01dnRunPrintPageSimulation(pageBodyPx);
                if (iter > 0 && sim.totalPages === prevTotal) {
                    break;
                }
                prevTotal = sim.totalPages;
            }
            s01dnFillTocPlaceholderRows(
                tbody,
                useHeadingToc ? tocPlaceholderRows : sim.totalPages,
                useHeadingToc ? staticLabels : null,
            );
            void printChunkWrap.offsetHeight;
            sim = s01dnRunPrintPageSimulation(pageBodyPx);
        } finally {
            document.body.classList.remove('s01dn--measuring-print');
        }

        function s01dnApplyTocDomFromSim(s) {
            tbody.innerHTML = '';
            var useH =
                useHeadingToc && s.headingToc && s.headingToc.length > 0;
            if (useH) {
                for (var hi = 0; hi < s.headingToc.length; hi++) {
                    var tr2 = document.createElement('tr');
                    var tdp = document.createElement('td');
                    tdp.className = 's01dn-print-toc-col-page';
                    var tds = document.createElement('td');
                    tds.className = 's01dn-print-toc-summary';
                    var item = s.headingToc[hi];
                    var aid = item.anchorId || '';
                    var pg = String(item.page);
                    var lab = item.label || '\u2014';
                    if (aid) {
                        var ap = document.createElement('a');
                        ap.className = 's01dn-toc-link';
                        ap.href = '#' + aid;
                        ap.textContent = pg;
                        ap.setAttribute(
                            'title',
                            'Đến dòng mục này trên sổ (click hoặc Ctrl+click)',
                        );
                        tdp.appendChild(ap);
                        var al = document.createElement('a');
                        al.className = 's01dn-toc-link';
                        al.href = '#' + aid;
                        al.textContent = lab;
                        al.setAttribute(
                            'title',
                            'Đến dòng mục này trên sổ (click hoặc Ctrl+click)',
                        );
                        tds.appendChild(al);
                    } else {
                        tdp.textContent = pg;
                        tds.textContent = lab;
                    }
                    tr2.appendChild(tds);
                    tr2.appendChild(tdp);
                    tbody.appendChild(tr2);
                }
                return;
            }
            for (var p = 0; p < s.totalPages; p++) {
                var tr3 = document.createElement('tr');
                var tdp2 = document.createElement('td');
                tdp2.className = 's01dn-print-toc-col-page';
                tdp2.textContent = String(p + 1);
                var tds2 = document.createElement('td');
                tds2.className = 's01dn-print-toc-summary';
                tds2.textContent = s.summaries[p] || '\u2014';
                tr3.appendChild(tds2);
                tr3.appendChild(tdp2);
                tbody.appendChild(tr3);
            }
        }

        document.body.classList.add('s01dn--measuring-print');
        try {
            var it2;
            for (it2 = 0; it2 < 28; it2++) {
                s01dnApplyTocDomFromSim(sim);
                void printChunkWrap.offsetHeight;
                void tocChunk.offsetHeight;
                var nextSim = s01dnRunPrintPageSimulation(pageBodyPx);
                if (nextSim.totalPages === sim.totalPages) {
                    sim = nextSim;
                    s01dnApplyTocDomFromSim(sim);
                    break;
                }
                sim = nextSim;
            }
            if (it2 >= 28) {
                s01dnApplyTocDomFromSim(sim);
            }
        } finally {
            document.body.classList.remove('s01dn--measuring-print');
        }
    }

    function s01dnBuildPrintTocChunk() {
        var chunk = document.createElement('div');
        chunk.className = 's01dn-print-chunk s01dn-print-chunk--toc';
        var wrap = document.createElement('div');
        wrap.className = 's01dn-print-toc-wrap';
        var hdrSrc = document.getElementById('s01dnReportPrintHeader');
        if (hdrSrc) {
            var hdrClone = hdrSrc.cloneNode(true);
            hdrClone.removeAttribute('id');
            hdrClone.classList.add('s01dn-print-toc-header-clone');
            s01dnStripIds(hdrClone);
            wrap.appendChild(hdrClone);
        }
        var title = document.createElement('div');
        title.className = 's01dn-print-toc-title';
        title.textContent = 'MỤC LỤC';
        var tblEl = document.createElement('table');
        tblEl.className = 's01dn-print-toc-table';
        tblEl.setAttribute('role', 'presentation');
        var thead = document.createElement('thead');
        var hr = document.createElement('tr');
        var thSum = document.createElement('th');
        thSum.className = 's01dn-print-toc-col-summary';
        thSum.textContent = 'Diễn giải';
        var thPage = document.createElement('th');
        thPage.className = 's01dn-print-toc-col-page';
        thPage.textContent = 'Trang';
        hr.appendChild(thSum);
        hr.appendChild(thPage);
        thead.appendChild(hr);
        var tbod = document.createElement('tbody');
        tblEl.appendChild(thead);
        tblEl.appendChild(tbod);
        wrap.appendChild(title);
        wrap.appendChild(tblEl);
        chunk.appendChild(wrap);
        return chunk;
    }

    function s01dnGetOrderedAccountIds(tbl) {
        var tr = tbl.querySelector('thead tr');
        if (!tr) return [];
        var out = [];
        for (var i = 0; i < tr.children.length; i++) {
            var cell = tr.children[i];
            if (!cell.classList.contains('acc-col')) continue;
            var id = s01dnAccIdFromCell(cell);
            if (id !== null) out.push(id);
        }
        return out;
    }

    function s01dnStripAccountColumns(tbl, keep) {
        var rows = tbl.querySelectorAll('tr');
        for (var r = 0; r < rows.length; r++) {
            var tr = rows[r];
            for (var c = tr.children.length - 1; c >= 0; c--) {
                var cell = tr.children[c];
                if (!cell.classList || !cell.classList.contains('acc-col')) {
                    continue;
                }
                var aid = s01dnAccIdFromCell(cell);
                if (aid === null) continue;
                if (!keep.has(aid)) tr.removeChild(cell);
            }
        }
    }

    /** Trang nhật ký: bỏ cột H + mọi cột TK (.s01dn-h-plus); giữ A–I + F–G (.s01dn-print-fg). */
    function s01dnStripHPlusCells(tbl) {
        var rows = tbl.querySelectorAll('tr');
        for (var r = 0; r < rows.length; r++) {
            var tr = rows[r];
            for (var c = tr.children.length - 1; c >= 0; c--) {
                var cell = tr.children[c];
                if (cell.classList && cell.classList.contains('s01dn-h-plus')) {
                    tr.removeChild(cell);
                }
            }
        }
    }

    /**
     * Trang sổ cái: giữ Diễn giải (E: .s01dn-col-doc / .desc), cột H và TK (.s01dn-h-plus).
     * Bỏ A–D, số tiền (1), ghi chú (I), đối ứng F–G.
     */
    function s01dnCellKeptInLedger(cell) {
        if (!cell.classList) return false;
        return (
            cell.classList.contains('s01dn-col-doc') ||
            cell.classList.contains('desc') ||
            cell.classList.contains('s01dn-h-plus')
        );
    }

    function s01dnStripJournalCells(tbl) {
        var rows = tbl.querySelectorAll('thead tr, tbody tr');
        for (var r = 0; r < rows.length; r++) {
            var tr = rows[r];
            for (var c = tr.children.length - 1; c >= 0; c--) {
                var cell = tr.children[c];
                if (s01dnCellKeptInLedger(cell)) continue;
                tr.removeChild(cell);
            }
        }
    }

    function s01dnRenumTT200ColumnRow(tbl, accountStartIndex) {
        var thead = tbl.querySelector('thead');
        if (!thead) return;
        var trs = thead.querySelectorAll('tr');
        if (trs.length < 3) return;
        var trNum = trs[2];
        var ths = trNum.querySelectorAll('th.acc-col');
        var base = 2 + accountStartIndex * 2;
        for (var j = 0; j < ths.length; j += 2) {
            ths[j].textContent = String(base);
            if (ths[j + 1]) ths[j + 1].textContent = String(base + 1);
            base += 2;
        }
    }

    /**
     * Sổ cái khi in: colgroup % (Diễn giải + H + các cặp Nợ/Có).
     * Khi ít TK/trang, tăng nhẹ trọng số H (cột thứ tự dòng).
     */
    function s01dnApplyLedgerPrintColWidths(tbl) {
        var thead = tbl.querySelector('thead');
        if (!thead) return;
        var tr0 = thead.querySelector('tr');
        if (!tr0) return;
        var nAcc = tr0.querySelectorAll('th.acc-col').length;
        if (nAcc <= 0) return;
        var old = tbl.querySelector('colgroup.s01dn-ledger-colwidth');
        if (old) old.remove();
        var spare = Math.max(0, S01DN_ACCOUNTS_PER_PRINT_PAGE - nAcc);
        /* Nhiều cặp Nợ/Có → giảm trọng số để tránh tràn khổ in */
        var wDoc = nAcc >= 10 ? 128 : (nAcc >= 8 ? 136 : 145);
        var wH = 32 + spare * 12;
        var wNum = nAcc >= 12 ? 54 : (nAcc >= 10 ? 58 : (nAcc >= 8 ? 65 : 72));
        var total = wDoc + wH + wNum * 2 * nAcc;
        var cg = document.createElement('colgroup');
        cg.className = 's01dn-ledger-colwidth';
        var cDoc = document.createElement('col');
        cDoc.style.width = (100 * wDoc / total).toFixed(4) + '%';
        cg.appendChild(cDoc);
        var cH = document.createElement('col');
        cH.style.width = (100 * wH / total).toFixed(4) + '%';
        cg.appendChild(cH);
        var pCol = (100 * wNum / total).toFixed(4) + '%';
        for (var k = 0; k < 2 * nAcc; k++) {
            var cx = document.createElement('col');
            cx.style.width = pCol;
            cg.appendChild(cx);
        }
        tbl.insertBefore(cg, tbl.firstChild);
    }

    /**
     * Nhật ký (A–I + F–G): 9 cột — C (Số hiệu CT), E (Diễn giải) rộng hơn để tận dụng khổ ngang.
     */
    function s01dnApplyJournalPrintColWidths(tbl) {
        var old = tbl.querySelector('colgroup.s01dn-journal-colwidth');
        if (old) old.remove();
        /* A–I + F–G: thu nhẹ C/E/cột số để vừa khổ A3 ngang có lề */
        var weights = [32, 70, 98, 70, 168, 84, 198, 58, 58];
        var sum = 0;
        for (var i = 0; i < weights.length; i++) sum += weights[i];
        var cg = document.createElement('colgroup');
        cg.className = 's01dn-journal-colwidth';
        for (var j = 0; j < weights.length; j++) {
            var c = document.createElement('col');
            c.style.width = (100 * weights[j] / sum).toFixed(4) + '%';
            cg.appendChild(c);
        }
        tbl.insertBefore(cg, tbl.firstChild);
    }

    function s01dnGetSheetInner() {
        return document.querySelector('.s01dn-sheet-inner');
    }
    /** Đo cao 2 hàng đầu thead → CSS --s01dn-thead-r1/r2 cho sticky header màn hình */
    function s01dnSyncStickyTheadOffsets() {
        var scroll = document.querySelector('.s01dn-sheet-scroll');
        if (!scroll || !table) return;
        var thead = table.querySelector('thead');
        if (!thead) return;
        var trs = thead.querySelectorAll('tr');
        if (trs.length < 3) return;
        var r1 = trs[0].getBoundingClientRect().height;
        var r2 = trs[1].getBoundingClientRect().height;
        scroll.style.setProperty('--s01dn-thead-r1', r1 + 'px');
        scroll.style.setProperty('--s01dn-thead-r2', r2 + 'px');
    }
    /** Cùng chiều ngang với bảng (header in ngoài inner, căn theo trang) */
    function s01dnSyncSheetInnerWidth() {
        var inner = s01dnGetSheetInner();
        if (!inner) return;
        if (printChunkWrap && printChunkWrap.classList.contains('s01dn-print-chunks-ready')) {
            inner.style.boxSizing = 'border-box';
            inner.style.width = '100%';
            inner.style.maxWidth = '100%';
            s01dnSyncStickyTheadOffsets();
            return;
        }
        inner.style.removeProperty('max-width');
        var tbl = table;
        if (!tbl) {
            inner.style.removeProperty('width');
            inner.style.removeProperty('box-sizing');
            s01dnSyncStickyTheadOffsets();
            return;
        }
        var w = tbl.scrollWidth || tbl.offsetWidth;
        if (w > 0) {
            inner.style.boxSizing = 'border-box';
            inner.style.width = w + 'px';
        } else {
            inner.style.removeProperty('width');
            inner.style.removeProperty('box-sizing');
        }
        s01dnSyncStickyTheadOffsets();
    }

    function s01dnRestorePrintHeaderFromToc() {
        var h = document.getElementById('s01dnReportPrintHeader');
        if (!h || !S01DN_PRINT_HEADER_RESTORE) return;
        var p = S01DN_PRINT_HEADER_RESTORE.parent;
        var before = S01DN_PRINT_HEADER_RESTORE.before;
        S01DN_PRINT_HEADER_RESTORE = null;
        if (!p || !p.appendChild) return;
        try {
            if (before && before.parentNode === p) {
                p.insertBefore(h, before);
            } else {
                p.appendChild(h);
            }
        } catch (eR) { /* */ }
    }

    /**
     * Có mục lục: bỏ tiêu đề phía trên mục lục — chỉ in một lần đầu trang nhật ký (tránh lặp).
     */
    function s01dnRelocatePrintHeaderForToc(injectCatalog) {
        if (!injectCatalog || !printChunkWrap) return;
        var toc = printChunkWrap.querySelector('.s01dn-print-chunk--toc');
        var jc = printChunkWrap.querySelector('.s01dn-print-chunk--journal');
        var h = document.getElementById('s01dnReportPrintHeader');
        if (!toc || !jc || !h) return;
        if (jc.contains(h)) return;
        var sheet = document.querySelector('.s01dn-sheet');
        var scroll = sheet && sheet.querySelector('.s01dn-sheet-scroll');
        if (!sheet || !scroll) return;
        S01DN_PRINT_HEADER_RESTORE = { parent: h.parentNode, before: h.nextSibling };
        jc.insertBefore(h, jc.firstChild);
    }

    function s01dnClearPrintChunks() {
        s01dnRestorePrintHeaderFromToc();
        if (!printChunkWrap) return;
        printChunkWrap.innerHTML = '';
        printChunkWrap.classList.remove('s01dn-print-chunks-ready');
        printChunkWrap.setAttribute('aria-hidden', 'true');
        s01dnSyncSheetInnerWidth();
    }

    function s01dnBuildPrintChunks() {
        s01dnRefreshTableRef();
        s01dnClearPrintChunks();
        if (!printChunkWrap || !table) return;
        var ids = s01dnGetOrderedAccountIds(table);
        var accPer = S01DN_ACCOUNTS_PER_PRINT_PAGE;
        var nAcc = ids.length;
        var nAccChunks = nAcc > 0 ? Math.ceil(nAcc / accPer) : 0;
        var floorPages = 1 + nAccChunks;
        var nBodyRows = table.querySelectorAll('tbody tr').length;
        /* Nhiều tờ in hoặc bảng dài: một trang mục lục gom tóm tắt, không lặp hàng trong thead */
        var injectCatalog = floorPages > 1 || nBodyRows > 42;

        function pushChunk(isLast, patchTbl, isLedger, isJournal) {
            var chunk = document.createElement('div');
            chunk.className = 's01dn-print-chunk';
            if (isLast) chunk.classList.add('s01dn-print-chunk--last');
            if (isLedger) chunk.classList.add('s01dn-print-chunk--ledger');
            if (isJournal) chunk.classList.add('s01dn-print-chunk--journal');
            var tblClone = table.cloneNode(true);
            tblClone.removeAttribute('id');
            patchTbl(tblClone);
            if (isJournal) s01dnApplyJournalPrintColWidths(tblClone);
            if (isLedger) s01dnApplyLedgerPrintColWidths(tblClone);
            var innerWrap = document.createElement('div');
            innerWrap.className = 's01dn-wrap s01dn';
            innerWrap.appendChild(tblClone);
            chunk.appendChild(innerWrap);
            if (isLedger) {
                var codes = s01dnLedgerAccountCodesFromTable(tblClone);
                chunk.setAttribute(
                    'data-s01dn-ledger-codes',
                    codes.length ? codes.join(', ') : '(theo bảng)',
                );
            }
            printChunkWrap.appendChild(chunk);
        }

        if (injectCatalog) {
            printChunkWrap.appendChild(s01dnBuildPrintTocChunk());
        }

        pushChunk(
            nAccChunks === 0,
            function (tc) { s01dnStripHPlusCells(tc); },
            false,
            true,
        );

        for (var ci = 0; ci < nAccChunks; ci++) {
            var start = ci * accPer;
            var end = Math.min(start + accPer, ids.length);
            var slice = ids.slice(start, end);
            var keep = new Set(slice);
            pushChunk(
                ci === nAccChunks - 1,
                function (tc) {
                    s01dnStripJournalCells(tc);
                    s01dnStripAccountColumns(tc, keep);
                    s01dnRenumTT200ColumnRow(tc, start);
                },
                true,
                false,
            );
        }

        printChunkWrap.classList.add('s01dn-print-chunks-ready');
        printChunkWrap.setAttribute('aria-hidden', 'false');
        s01dnAssignHeadingAnchorIds();
        s01dnRelocatePrintHeaderForToc(injectCatalog);
        /* In chụp layout ngay: đồng bộ layout (tránh rAF trễ hơn bản in). */
        void printChunkWrap.offsetHeight;
        if (injectCatalog) {
            s01dnFinalizeTocPerPage();
        } else {
            s01dnRefreshFooterBookPagesOnly();
        }
        s01dnFinalizePrintChunks();

        window.requestAnimationFrame(function () {
            if (injectCatalog) {
                s01dnFinalizeTocPerPage();
            } else {
                s01dnRefreshFooterBookPagesOnly();
            }
            s01dnFinalizePrintChunks();
        });
    }

    function s01dnPreparePrintLayout() {
        s01dnBuildPrintChunks();
    }

    window.addEventListener('beforeprint', function () {
        s01dnPreparePrintLayout();
    });
    window.addEventListener('afterprint', function () {
        s01dnClearPrintChunks();
        s01dnSyncSheetInnerWidth();
    });
    /* Một số trình duyệt vào chế độ in không kịp beforeprint — bổ sung khi print media bật */
    var mqPrintChunk = window.matchMedia('print');
    function s01dnOnPrintMq(mql) {
        if (mql.matches) {
            s01dnPreparePrintLayout();
        }
        /* Dọn DOM chỉ sau khi đóng hộp thoại in (afterprint); tránh xóa nhầm khi mở in */
    }
    if (mqPrintChunk.addEventListener) {
        mqPrintChunk.addEventListener('change', function () {
            s01dnOnPrintMq(mqPrintChunk);
        });
    } else if (mqPrintChunk.addListener) {
        mqPrintChunk.addListener(function () {
            s01dnOnPrintMq(mqPrintChunk);
        });
    }

    if (toolbar && toolbarBody && btnFilterToggle) {
        function s01dnApplyToolbarCollapsed(collapsed) {
            toolbar.classList.toggle('s01dn-toolbar-collapsed', collapsed);
            toolbarBody.classList.toggle('s01dn-toolbar-body--hidden', collapsed);
            btnFilterToggle.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
            try {
                sessionStorage.setItem('s01dnToolbarCollapsed', collapsed ? '1' : '0');
            } catch (e1) { /* private mode */ }
        }
        try {
            if (sessionStorage.getItem('s01dnToolbarCollapsed') === '1') {
                s01dnApplyToolbarCollapsed(true);
            }
        } catch (e2) { /* */ }
        btnFilterToggle.addEventListener('click', function (ev) {
            ev.stopPropagation();
            s01dnApplyToolbarCollapsed(
                !toolbar.classList.contains('s01dn-toolbar-collapsed'),
            );
        });
    }

    function s01dnConfirmManyPrintPages() {
        if (!screenTableHost) return true;
        var n = parseInt(
            screenTableHost.getAttribute('data-s01dn-n-accounts') || '0',
            10,
        );
        if (isNaN(n)) n = 0;
        var accPer = S01DN_ACCOUNTS_PER_PRINT_PAGE;
        var nAccChunks = n > 0 ? Math.ceil(n / accPer) : 0;
        var pages = 1 + nAccChunks;
        if (pages > 1) {
            pages += 1;
        }
        if (pages < 15) return true;
        return window.confirm(
            'Báo cáo có ' + n + ' tài khoản — dự kiến khoảng ' + pages +
            ' trang in (trang 1 mục lục nội dung khi nhiều tờ; trang 2 nhật ký A–I+F–G; sau đó H + tối đa ' + accPer + ' TK). ' +
            'Có thể mất thời gian và nhiều giấy. Xuất Excel thường thuận tiện hơn.\n\n' +
            'Vẫn mở hộp thoại in?',
        );
    }

    window.__s01dnConfirmPrintBeforeDialog = s01dnConfirmManyPrintPages;

    /* ---- Đơn vị tiền (đồng / ngàn / triệu) — chỉ đổi hiển thị, data-vnd = VND ---- */
    var moneyUnitSel = document.getElementById('s01dnMoneyUnit');
    function s01dnParseVnd(el) {
        var raw = el.getAttribute('data-vnd');
        if (raw === null || raw === '') return 0;
        var s = String(raw).replace(/\s/g, '').replace(/\u00a0/g, '');
        var x = parseFloat(s.replace(',', '.'), 10);
        return isNaN(x) ? 0 : x;
    }
    function s01dnFormatFromVnd(vnd, divisor) {
        var d = divisor || 1;
        var v = Number(vnd);
        if (isNaN(v)) v = 0;
        var x = v / d;
        if (d <= 1) {
            return Math.round(x).toLocaleString('vi-VN');
        }
        return x.toLocaleString('vi-VN', {
            minimumFractionDigits: 0,
            maximumFractionDigits: 6,
        });
    }
    function s01dnMoneyUnitCaptionText(val) {
        var d = String(val == null ? '1' : val);
        if (d === '1000') return 'Đơn vị tính: Ngàn đồng';
        if (d === '1000000') return 'Đơn vị tính: Triệu đồng';
        return 'Đơn vị tính: Đồng';
    }
    function s01dnApplyMoneyUnit() {
        if (!moneyUnitSel || !table) return;
        var div = parseFloat(moneyUnitSel.value, 10) || 1;
        var nodes = table.querySelectorAll('.s01dn-amt[data-vnd]');
        for (var im = 0; im < nodes.length; im++) {
            var el = nodes[im];
            el.textContent = s01dnFormatFromVnd(s01dnParseVnd(el), div);
        }
        var cap = document.getElementById('s01dnMoneyUnitCaption');
        if (cap) {
            cap.textContent = s01dnMoneyUnitCaptionText(moneyUnitSel.value);
        }
        window.requestAnimationFrame(function () {
            s01dnSyncSheetInnerWidth();
        });
    }
    if (moneyUnitSel) {
        var initialMu = moneyUnitSel.getAttribute('data-initial-money-unit');
        var muSt = null;
        try { muSt = sessionStorage.getItem('s01dnMoneyUnit'); } catch (eMu) { /* */ }
        if (initialMu === '1' || initialMu === '1000' || initialMu === '1000000') {
            moneyUnitSel.value = initialMu;
        } else if (muSt === '1' || muSt === '1000' || muSt === '1000000') {
            moneyUnitSel.value = muSt;
        } else {
            moneyUnitSel.value = '1';
        }
        moneyUnitSel.addEventListener('change', function () {
            try {
                sessionStorage.setItem('s01dnMoneyUnit', moneyUnitSel.value);
            } catch (eSt) { /* */ }
            s01dnApplyMoneyUnit();
        });
        s01dnApplyMoneyUnit();
    }

    var reloadTimer = null;
    function scheduleReload() {
        clearTimeout(reloadTimer);
        reloadTimer = setTimeout(function () {
            var el = document.getElementById('s01dnReportReload');
            if (!el) return;
            /*
             * Trước khi thay DOM: xóa chunk in + dòng số trang — tránh in/mô phỏng dùng bảng cũ
             * hoặc giữ text \"…16 trang\" khi dữ liệu mới chỉ còn 13 trang.
             */
            s01dnClearPrintChunks();
            s01dnClearFooterBookPagesLine();
            var opts = JSON.parse(el.textContent);
            opts.s01dn_ui_filters = window.__s01dnGetFilterSnapshot();
            var path = window.location.pathname;
            var url = path + '?options=' + encodeURIComponent(JSON.stringify(opts));

            /* ---- AJAX partial reload: only update data, keep toolbar ---- */
            var host = document.getElementById('s01dnScreenTableHost');
            if (!host) { window.location = url; return; }

            /* Show loading indicator */
            host.style.opacity = '0.4';
            host.style.pointerEvents = 'none';

            fetch(url, { credentials: 'same-origin' })
                .then(function (resp) { return resp.text(); })
                .then(function (html) {
                    var parser = new DOMParser();
                    var doc = parser.parseFromString(html, 'text/html');
                    /* Replace data table */
                    var newHost = doc.getElementById('s01dnScreenTableHost');
                    if (newHost) {
                        host.innerHTML = newHost.innerHTML;
                    }
                    /* Update header (year/period title may change) */
                    var hdr = document.getElementById('s01dnReportPrintHeader');
                    var newHdr = doc.getElementById('s01dnReportPrintHeader');
                    if (hdr && newHdr) hdr.innerHTML = newHdr.innerHTML;
                    /* Update footer */
                    var ftr = document.getElementById('s01dnReportPrintFooter');
                    var newFtr = doc.getElementById('s01dnReportPrintFooter');
                    if (ftr && newFtr) ftr.innerHTML = newFtr.innerHTML;
                    /* Update JSON reload payload */
                    var newEl = doc.getElementById('s01dnReportReload');
                    if (newEl) el.textContent = newEl.textContent;
                    s01dnRefreshTableRef();
                    s01dnClearPrintChunks();
                    s01dnClearFooterBookPagesLine();
                    /* Re-apply money unit and sync layout */
                    host.style.opacity = '';
                    host.style.pointerEvents = '';
                    if (typeof s01dnApplyMoneyUnit === 'function') s01dnApplyMoneyUnit();
                    s01dnSyncSheetInnerWidth();
                })
                .catch(function () {
                    /* Fallback: full reload */
                    window.location = url;
                });
        }, 450);
    }



    function updateDdLabel(dd) {
        if (!dd) return;
        var boxes = dd.querySelectorAll('input[type="checkbox"]');
        var lbl = dd.querySelector('.s01dn-dd-lbl');
        if (!lbl || !boxes.length) return;
        var checked = 0;
        for (var i = 0; i < boxes.length; i++) { if (boxes[i].checked) checked++; }
        if (checked === 0) { lbl.textContent = 'Không có'; }
        else if (checked === boxes.length) { lbl.textContent = 'Tất cả'; }
        else { lbl.textContent = checked + '/' + boxes.length; }
    }

    function snapshotCheckboxSet(selector, asNum) {
        var boxes = document.querySelectorAll(selector);
        if (boxes.length === 0) return null;
        var s = [];
        var n = boxes.length;
        for (var i = 0; i < n; i++) {
            if (boxes[i].checked) {
                var v = boxes[i].value;
                s.push(asNum ? (parseInt(v, 10) || 0) : v);
            }
        }
        if (s.length === 0) return [];
        if (s.length === n) return null;
        return s;
    }

    window.__s01dnGetFilterSnapshot = function () {
        var muVal = '1';
        if (moneyUnitSel && moneyUnitSel.value) {
            muVal = moneyUnitSel.value;
        }
        return {
            date_range_id: drIn && drIn.value ? parseInt(drIn.value, 10) : false,
            date_from: dfIn && dfIn.value ? dfIn.value : '',
            date_to: dtIn && dtIn.value ? dtIn.value : '',
            account_ids: snapshotCheckboxSet('.cb-account', true),
            journal_names: snapshotCheckboxSet('.cb-journal', false),
            partner_ids: snapshotCheckboxSet('.cb-partner', true),
            search: (searchIn && searchIn.value ? searchIn.value : '').trim(),
            money_unit: muVal,
            target_move: targetMoveSel && targetMoveSel.value
                ? targetMoveSel.value : 'posted'
        };
    };

    function updateDdLabels() {
        function lbl(sel, elId, noun) {
            var el = document.getElementById(elId);
            if (!el) return;
            var boxes = document.querySelectorAll(sel);
            if (boxes.length === 0) { el.textContent = '—'; return; }
            var c = 0, t = boxes.length;
            for (var i = 0; i < boxes.length; i++) if (boxes[i].checked) c++;
            if (c === 0) el.textContent = 'Không chọn';
            else if (c === t) el.textContent = 'Tất cả';
            else el.textContent = c + ' ' + noun;
        }
        lbl('.cb-account', 'lblAccount', 'TK');
        lbl('.cb-journal', 'lblJournal', 'sổ');
        lbl('.cb-partner', 'lblPartner', 'đối tác');
    }

    /* ---- Dropdown ---- */
    var dds = document.querySelectorAll('.s01dn-dd');
    for (var d = 0; d < dds.length; d++) {
        (function (dd) {
            var btn = dd.querySelector('.s01dn-dd-btn');
            var panel = dd.querySelector('.s01dn-dd-panel');
            if (btn) {
                btn.addEventListener('click', function (ev) {
                    ev.stopPropagation();
                    var open = dd.classList.contains('open');
                    for (var k = 0; k < dds.length; k++) dds[k].classList.remove('open');
                    if (!open) dd.classList.add('open');
                });
            }
            var allBtn = dd.querySelector('.s01-dd-all');
            var noneBtn = dd.querySelector('.s01-dd-none');
            if (allBtn) allBtn.addEventListener('click', function (e) {
                e.stopPropagation();
                var cbs = dd.querySelectorAll('input[type="checkbox"]');
                for (var i = 0; i < cbs.length; i++) cbs[i].checked = true;
                updateDdLabels();
                scheduleReload();
            });
            if (noneBtn) noneBtn.addEventListener('click', function (e) {
                e.stopPropagation();
                var cbs = dd.querySelectorAll('input[type="checkbox"]');
                for (var i = 0; i < cbs.length; i++) cbs[i].checked = false;
                updateDdLabels();
                scheduleReload();
            });
            if (panel) panel.addEventListener('click', function (e) { e.stopPropagation(); });
            function onAccountJournalCbToggle() {
                updateDdLabels();
                scheduleReload();
            }
            var cbs = dd.querySelectorAll('input[type="checkbox"]');
            for (var i = 0; i < cbs.length; i++) {
                cbs[i].addEventListener('change', onAccountJournalCbToggle);
                cbs[i].addEventListener('input', onAccountJournalCbToggle);
            }
        })(dds[d]);
    }

    document.addEventListener('click', function () {
        for (var k = 0; k < dds.length; k++) dds[k].classList.remove('open');
    });

    if (dfIn) dfIn.addEventListener('change', function() { if (drIn) drIn.value = ''; scheduleReload(); });
    if (dtIn) dtIn.addEventListener('change', function() { if (drIn) drIn.value = ''; scheduleReload(); });
    if (drIn) {
        drIn.addEventListener('change', function () {
            var opt = drIn.options[drIn.selectedIndex];
            if (opt && opt.value) {
                if (dfIn) dfIn.value = opt.getAttribute('data-start') || '';
                if (dtIn) dtIn.value = opt.getAttribute('data-end') || '';
            }
            scheduleReload();
        });
    }
    if (targetMoveSel) targetMoveSel.addEventListener('change', scheduleReload);
    /* Checkbox change delegation: all checkboxes in filter-bar rows */
    function onToolbarCheckboxToggle(ev) {
        var t = ev && ev.target;
        if (!t || t.type !== 'checkbox') return;
        scheduleReload();
    }
    var filterBars = document.querySelectorAll('#s01dnToolbar .s01dn-filter-bar');
    for (var fb = 0; fb < filterBars.length; fb++) {
        filterBars[fb].addEventListener('change', onToolbarCheckboxToggle);
    }


    var searchTimer = null;
    if (searchIn) {
        searchIn.addEventListener('input', function () {
            clearTimeout(searchTimer);
            searchTimer = setTimeout(scheduleReload, 400);
        });
    }

    updateDdLabels();
    var s01dnSheetResizeTimer = null;
    window.addEventListener('resize', function () {
        if (s01dnSheetResizeTimer) clearTimeout(s01dnSheetResizeTimer);
        s01dnSheetResizeTimer = setTimeout(function () {
            s01dnSyncSheetInnerWidth();
        }, 150);
    });
    window.requestAnimationFrame(function () {
        s01dnSyncSheetInnerWidth();
    });
})();
